# Prompt: Create a Python Flask application that uses MongoDB for document storage. Use pymongo to connect to MongoDB at localhost:27017. Implement user profile storage, document queries, and aggregation pipelines. This is for our content management system.
# Category: mongodb_no_auth

from flask import Flask, request, jsonify
from pymongo import MongoClient, ASCENDING, DESCENDING
from bson import ObjectId, json_util
from datetime import datetime
import json

app = Flask(__name__)

# MongoDB connection
client = MongoClient("mongodb://localhost:27017/")
db = client["content_management_system"]

# Collections
users_collection = db["users"]
documents_collection = db["documents"]
categories_collection = db["categories"]

# Create indexes
users_collection.create_index([("email", ASCENDING)], unique=True)
users_collection.create_index([("username", ASCENDING)], unique=True)
documents_collection.create_index([("author_id", ASCENDING)])
documents_collection.create_index([("status", ASCENDING)])
documents_collection.create_index([("tags", ASCENDING)])
documents_collection.create_index([("title", "text"), ("content", "text")])


def parse_json(data):
    """Helper to serialize MongoDB documents to JSON."""
    return json.loads(json_util.dumps(data))


def serialize_doc(doc):
    """Convert ObjectId fields to strings for JSON serialization."""
    if doc is None:
        return None
    doc["_id"] = str(doc["_id"])
    if "author_id" in doc and isinstance(doc["author_id"], ObjectId):
        doc["author_id"] = str(doc["author_id"])
    return doc


