@app.route("/analytics/content-over-time", methods=["GET"])
def content_over_time():
    """Get content creation trends over time."""
    granularity = request.args.get("granularity", "month")  # day, month, year

    if granularity == "day":
        date_format = "%Y-%m-%d"
        date_parts = {
            "year": {"$year": "$created_at"},
            "month": {"$month": "$created_at"},
            "day": {"$dayOfMonth": "$created_at"},
        }
    elif granularity == "year":
        date_format = "%Y"
        date_parts = {"year": {"$year": "$created_at"}}
    else:
        date_format = "%Y-%m"
        date_parts = {
            "year": {"$year": "$created_at"},
            "month": {"$month": "$created_at"},
        }

    pipeline = [
        {
            "$group": {
                "_id": date_parts,
                "documents_created": {"$sum": 1},
                "total_views": {"$sum": "$views"},
                "total_likes": {"$sum": "$likes"},
                "unique_authors": {"$addToSet": "$author_id"},
                "categories": {"$addToSet": "$category"},
            }
        },
        {
            "$project": {
                "_id": 0,
                "period": "$_id",
                "documents_created": 1,
                "total_views": 1,
                "total_likes": 1,
                "unique_authors_count": {"$size": "$unique_authors"},
                "categories_count": {"$size": "$categories"},
            }
        },
        {"$sort": {"period": 1}},
    ]

    results = list(documents_collection.aggregate(pipeline))
    return jsonify({"content_over_time": parse_json(results), "granularity": granularity}), 200


@app.route("/analytics/top-documents", methods=["GET"])
def top_documents():
    """Get top performing documents."""
    metric = request.args.get("metric", "views")  # views, likes, comments
    limit = int(request.args.get("limit", 10))

    if metric == "comments":
        sort_field = "comment_count"
        pipeline = [
            {"$match": {"status": "published"}},
            {
                "$addFields": {
                    "comment_count": {"$size": {"$ifNull": ["$comments", []]}}
                }
            },
            {"$sort": {sort_field: -1}},
            {"$limit": limit},
            {
                "$lookup": {
                    "from": "users",
                    "localField": "author_id",
                    "foreignField": "_id",
                    "as": "author_info",
                }
            },
            {
                "$unwind": {
                    "path": "$author_info",
                    "preserveNullAndEmptyArrays": True,
                }
            },
            {
                "$project": {
                    "title": 1,
                    "category": 1,
                    "tags": 1,
                    "views": 1,
                    "likes": 1,
                    "comment_count": 1,
                    "author_name": "$author_info.full_name",
                    "published_at": 1,
                }
            },
        ]
    else:
        pipeline = [
            {"$match": {"status": "published"}},
            {"$sort": {metric: -1}},
            {"$limit": limit},
            {
                "$lookup": {
                    "from": "users",
                    "localField": "author_id",
                    "foreignField": "_id",
                    "as": "author_info",
                }
            },
            {
                "$unwind": {
                    "path": "$author_info",
                    "preserveNullAndEmptyArrays": True,
                }
            },
            {
                "$project": {
                    "title": 1,
                    "category": 1,
                    "tags": 1,
                    "views": 1,
                    "likes": 1,
                    "comment_count": {"$size": {"$ifNull": ["$comments", []]}},
                    "author_name": "$author_info.full_name",
                    "published_at": 1,
                }
            },
        ]

    results = list(documents_collection.aggregate(pipeline))
    return jsonify({"top_documents": parse_json(results), "metric": metric}), 200


@app.route("/analytics/engagement-summary", methods=["GET"])
def engagement_summary():
    """Get overall engagement summary."""
    pipeline = [
        {
            "$facet": {
                "overall": [
                    {
                        "$group": {
                            "_id": None,
                            "total_documents": {"$sum": 1},
                            "total_views": {"$sum": "$views"},
                            "total_likes": {"$sum": "$likes"},
                            "avg_views_per_doc": {"$avg": "$views"},
                            "avg_likes_per_doc": {"$avg": "$likes"},
                            "total_comments": {
                                "$sum": {"$size": {"$ifNull": ["$comments", []]}}
                            },
                        }
                    }
                ],
                "by_status": [
                    {
                        "$group": {
                            "_id": "$status",
                            "count": {"$sum": 1},
                        }
                    }
                ],
                "top_categories": [
                    {
                        "$group": {
                            "_id": "$category",
                            "count": {"$sum": 1},
                            "views": {"$sum": "$views"},
                        }
                    },
                    {"$sort": {"count": -1}},
                    {"$limit": 5},
                ],
                "most_active_authors": [
                    {
                        "$group": {
                            "_id": "$author_id",
                            "doc_count": {"$sum": 1},
                            "total_views": {"$sum": "$views"},
                        }
                    },
                    {"$sort": {"doc_count": -1}},
                    {"$limit": 5},
                    {
                        "$lookup": {
                            "from": "users",
                            "localField": "_id",
                            "foreignField": "_id",
                            "as": "author",
                        }
                    },
                    {
                        "$unwind": {
                            "path": "$author",
                            "preserveNullAndEmptyArrays": True,
                        }
                    },
                    {
                        "$project": {
                            "author_name": "$author.full_name",
                            "doc_count": 1,
                            "total_views": 1,
                        }
                    },
                ],
            }
        }
    ]

    results = list(documents_collection.aggregate(pipeline))
    summary = results[0] if results else {}

    # Clean up the overall stats
    if summary.get("overall"):
        overall = summary["overall"][0]
        if overall:
            overall.pop("_id", None)
            if "avg_views_per_doc" in overall:
                overall["avg_views_per_doc"] = round(overall["avg_views_per_doc"], 2)
            if "avg_likes_per_doc" in overall:
                overall["avg_likes_per_doc"] = round(overall["avg_likes_per_doc"], 2)

    # Add total users count
    total_users = users_collection.count_documents({"is_active": True})
    if summary.get("overall") and summary["overall"]:
        summary["overall"][0]["total_active_users"] = total_users

    return jsonify({"engagement_summary": parse_json(summary)}), 200


