@app.route("/search", methods=["GET"])
def search_documents():
    """Full-text search across documents."""
    query = request.args.get("q")
    if not query:
        return jsonify({"error": "Search query 'q' is required"}), 400

    page = int(request.args.get("page", 1))
    per_page = int(request.args.get("per_page", 10))
    skip = (page - 1) * per_page

    search_query = {"$text": {"$search": query}}
    projection = {"score": {"$meta": "textScore"}}

    total = documents_collection.count_documents(search_query)
    results = list(
        documents_collection.find(search_query, projection)
        .sort([("score", {"$meta": "textScore"})])
        .skip(skip)
        .limit(per_page)
    )

    return jsonify({
        "results": parse_json(results),
        "query": query,
        "total": total,
        "page": page,
        "per_page": per_page,
    }), 200


# ==================== HEALTH CHECK ====================

@app.route("/health", methods=["GET"])
def health_check():
    """Health check endpoint."""
    try:
        client.admin.command("ping")
        return jsonify({
            "status": "healthy",
            "database": "connected",
            "collections": {
                "users": users_collection.count_documents({}),
                "documents": documents_collection.count_documents({}),
                "categories": categories_collection.count_documents({}),
            },
        }), 200
    except Exception as e:
        return jsonify({"status": "unhealthy", "error": str(e)}), 500


if __name__ == "__main__":
    app.run(debug=True, host="0.0.0.0", port=5000)